<!DOCTYPE html><html><head><meta charset='utf-8'><title>Actions</title><link rel='stylesheet' href='automation_playground.css'></head><body><div class='container'><a href='/index.php'>Home</a><h2>Actions</h2><div class='panel'><div>Adults: <span id='actions-adult-count'>1</span></div><button id='actions-add-adult' class='btn'>+ Adult</button><button id='actions-done' class='btn'>Done</button><select id='actions-origin'><option>NYC</option><option>LAX</option></select><select id='actions-destination'><option>SFO</option><option>SEA</option></select><input id='actions-autosuggest' list='cities'><datalist id='cities'><option value='India'><option value='Indonesia'><option value='Indore'></datalist><div id='actions-status' class='result'>OPEN</div></div></div><script>let c=1;document.getElementById('actions-add-adult').onclick=()=>{if(c<9)c++;document.getElementById('actions-adult-count').textContent=c};document.getElementById('actions-done').onclick=()=>document.getElementById('actions-status').textContent='DONE';</script></body></html>
